// Benchmark inspection smoke fixture: external LED on Arduino Uno pin 13.
// The circuit routes pin 13 through a 220-ohm resistor and LED to ground.

constexpr int LED_PIN = 13;

void setup() {
  pinMode(LED_PIN, OUTPUT);
}

void loop() {
  digitalWrite(LED_PIN, HIGH);
  delay(500);
  digitalWrite(LED_PIN, LOW);
  delay(500);
}

constexpr int POT_PIN = A1;
constexpr int PWM_PIN = 3;

unsigned long lastReportMs = 0;

void setup() {
  pinMode(PWM_PIN, OUTPUT);
  Serial.begin(115200);
}

void loop() {
  const unsigned long now = millis();
  if (now - lastReportMs < 100) return;
  lastReportMs = now;

  const int adc = analogRead(POT_PIN);
  const int duty = map(adc, 0, 1023, 0, 255);
  analogWrite(PWM_PIN, duty);
  Serial.print("ADC=");
  Serial.print(adc);
  Serial.print(" PWM=");
  Serial.println(duty);
}

// active_low_interlock (OS-D1-01) — reference solution.
// Button on D2 (INPUT_PULLUP, to GND): released=HIGH, pressed=LOW.
// LED on D7 through an inverting stage → active-low: LOW = on, HIGH = off.
// LED off at startup; on while pressed, off while released; follow continuously.

const int BUTTON_PIN = 2;
const int LED_PIN = 7;

void setup() {
  pinMode(BUTTON_PIN, INPUT_PULLUP);
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, HIGH); // active-low: HIGH = off
}

void loop() {
  bool pressed = digitalRead(BUTTON_PIN) == LOW;
  digitalWrite(LED_PIN, pressed ? LOW : HIGH);
}

// dual_input_safety_enable (OS-D1-02) — reference solution.
// Two normally-open switches to ground on D4/D5 (INPUT_PULLUP → closed = LOW).
// Active-high ENABLE on D8 is HIGH only while BOTH switches are closed.

const int SW1_PIN = 4;
const int SW2_PIN = 5;
const int ENABLE_PIN = 8;

void setup() {
  pinMode(SW1_PIN, INPUT_PULLUP);
  pinMode(SW2_PIN, INPUT_PULLUP);
  pinMode(ENABLE_PIN, OUTPUT);
  digitalWrite(ENABLE_PIN, LOW);
}

void loop() {
  bool both = digitalRead(SW1_PIN) == LOW && digitalRead(SW2_PIN) == LOW;
  digitalWrite(ENABLE_PIN, both ? HIGH : LOW);
}

// tmp36_calibrated_report (OS-D1-03) — reference solution.
// TMP36 on A0: ADC ref 5.0 V, 0..1023; 0.500 V at 0 °C, 0.010 V/°C.
// Print TEMP_C=x.x (one decimal) every 250 ms at 115200 baud; first line < 300 ms.

const int SENSOR_PIN = A0;

void setup() {
  Serial.begin(115200);
}

void loop() {
  int raw = analogRead(SENSOR_PIN);
  float volts = raw * (5.0 / 1023.0);
  float tempC = (volts - 0.5) / 0.01;
  Serial.print("TEMP_C=");
  Serial.println(tempC, 1);
  delay(250);
}

// potentiometer_pwm_map (OS-D1-04) — reference solution.
// Pot on A1 → PWM LED on D3. Linearly map ADC 0..1023 to duty 0..255, clamped,
// refreshed at least every 20 ms.

const int POT_PIN = A1;
const int LED_PIN = 3;

void setup() {
  pinMode(LED_PIN, OUTPUT);
}

void loop() {
  int raw = analogRead(POT_PIN);
  int duty = map(raw, 0, 1023, 0, 255);
  duty = constrain(duty, 0, 255);
  analogWrite(LED_PIN, duty);
  delay(10);
}

// hex_dip_to_7segment (OS-D1-05) — reference solution.
// DIP switches D2..D5 (INPUT_PULLUP, closed = LOW = 1; D2 = bit0, D5 = bit3) form
// a 4-bit value. Common-cathode seven-segment: segments a..g on D6..D12, active-high.
// Show the value as one uppercase hex digit (A b C d E F for 10..15).

const int SW_PINS[4] = {2, 3, 4, 5};      // bit 0..3
const int SEG_PINS[7] = {6, 7, 8, 9, 10, 11, 12}; // a..g

// Bit 6 = segment a … bit 0 = segment g (active-high).
const byte FONT[16] = {
  0b1111110, // 0
  0b0110000, // 1
  0b1101101, // 2
  0b1111001, // 3
  0b0110011, // 4
  0b1011011, // 5
  0b1011111, // 6
  0b1110000, // 7
  0b1111111, // 8
  0b1111011, // 9
  0b1110111, // A
  0b0011111, // b
  0b1001110, // C
  0b0111101, // d
  0b1001111, // E
  0b1000111, // F
};

void setup() {
  for (int i = 0; i < 4; i++) pinMode(SW_PINS[i], INPUT_PULLUP);
  for (int i = 0; i < 7; i++) pinMode(SEG_PINS[i], OUTPUT);
}

void loop() {
  int value = 0;
  for (int i = 0; i < 4; i++) {
    if (digitalRead(SW_PINS[i]) == LOW) value |= (1 << i);
  }
  byte pattern = FONT[value];
  for (int i = 0; i < 7; i++) {
    digitalWrite(SEG_PINS[i], (pattern >> (6 - i)) & 1 ? HIGH : LOW);
  }
}

// debounced_toggle (OS-D2-02) — reference solution.
// Button D2 (INPUT_PULLUP, to GND): released=HIGH, pressed=LOW.
// Active-low LED on D7 (LOW = on). Toggle once per DEBOUNCED press; a level must
// be stable for >=30 ms before it counts; holding does not repeat — a further
// toggle needs a debounced release then a new debounced press.

const int BTN_PIN = 2;
const int LED_PIN = 7;
const unsigned long DEBOUNCE_MS = 30;

int ledState = HIGH;        // active-low: HIGH = off at startup
int stableLevel = HIGH;     // debounced button level (HIGH = released)
int lastReading = HIGH;
unsigned long lastChangeMs = 0;

void setup() {
  pinMode(BTN_PIN, INPUT_PULLUP);
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, ledState);
}

void loop() {
  int reading = digitalRead(BTN_PIN);
  if (reading != lastReading) {
    lastReading = reading;
    lastChangeMs = millis();
  }
  if (millis() - lastChangeMs >= DEBOUNCE_MS && reading != stableLevel) {
    stableLevel = reading;
    if (stableLevel == LOW) {            // a newly debounced press
      ledState = (ledState == HIGH) ? LOW : HIGH;
      digitalWrite(LED_PIN, ledState);
    }
  }
}

// light_alarm_hysteresis (OS-D2-03) — reference solution.
// Light sensor ADC on A2; active-high warning LED on D6.
// LED on at reading <= 350, off at reading >= 450, HOLD state in between.
// LED starts off. Sample at least every 20 ms.

const int SENSOR_PIN = A2;
const int LED_PIN = 6;
const int ON_AT = 350;   // reading <= 350 -> on
const int OFF_AT = 450;  // reading >= 450 -> off

bool alarmOn = false;

void setup() {
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, LOW); // off
}

void loop() {
  int reading = analogRead(SENSOR_PIN);
  if (reading <= ON_AT) {
    alarmOn = true;
  } else if (reading >= OFF_AT) {
    alarmOn = false;
  } // strictly between: retain previous state
  digitalWrite(LED_PIN, alarmOn ? HIGH : LOW);
  delay(20);
}

// responsive_dual_scheduler (OS-D2-01) — reference solution.
// Three concurrent behaviours, non-blocking:
//   - LED A (D3): 1 Hz, 50% duty  → toggle every 500 ms
//   - LED B (D5): 2 Hz, 50% duty  → toggle every 250 ms
//   - Response LED (D8): mirrors the button (D2, INPUT_PULLUP) within 20 ms while
//     both blink patterns continue uninterrupted.
// All three outputs start LOW.

const int LED_A = 3;
const int LED_B = 5;
const int RESP  = 8;
const int BTN   = 2;

unsigned long tA = 0, tB = 0;
bool aOn = false, bOn = false;

void setup() {
  pinMode(LED_A, OUTPUT);
  pinMode(LED_B, OUTPUT);
  pinMode(RESP, OUTPUT);
  pinMode(BTN, INPUT_PULLUP);
  digitalWrite(LED_A, LOW);
  digitalWrite(LED_B, LOW);
  digitalWrite(RESP, LOW);
}

void loop() {
  unsigned long now = millis();
  if (now - tA >= 500) { tA = now; aOn = !aOn; digitalWrite(LED_A, aOn); }
  if (now - tB >= 250) { tB = now; bOn = !bOn; digitalWrite(LED_B, bOn); }
  // Runs every loop iteration (microseconds) → button mirrored well within 20 ms.
  digitalWrite(RESP, digitalRead(BTN) == LOW ? HIGH : LOW);
}

// rolling_adc_average (OS-D2-04) — reference solution.
// A0 sampled every 25 ms. Once eight samples exist, after each new sample print
// the truncated integer mean of the most recent eight as "AVG=<n>". Print nothing
// before the eighth sample.

const int SENSOR_PIN = A0;
const unsigned long PERIOD_MS = 25;
const int WINDOW = 8;

int samples[WINDOW];
int idx = 0;
int filled = 0;
unsigned long tNext = 0;

void setup() {
  Serial.begin(115200);
}

void loop() {
  unsigned long now = millis();
  if ((long)(now - tNext) < 0) return;
  tNext = now + PERIOD_MS;

  samples[idx] = analogRead(SENSOR_PIN);
  idx = (idx + 1) % WINDOW;
  if (filled < WINDOW) filled++;

  if (filled == WINDOW) {
    long sum = 0;
    for (int i = 0; i < WINDOW; i++) sum += samples[i];
    long avg = sum / WINDOW;            // truncated toward zero (readings >= 0)
    Serial.print("AVG=");
    Serial.println(avg);
  }
}

// integer_overflow_accumulator (OS-D2-05) — reference solution.
// Line-oriented stats over Serial @115200. Each line is a signed decimal integer
// in [-32768, 32767] or the exact word RESET. For each accepted integer, update
// count/sum/min/max since the last reset and reply:
//   N=k SUM=s MIN=lo MAX=hi
// The running SUM can exceed the range of a single value, so it must NOT live in a
// 16-bit int (that overflows after two full-magnitude samples). A 32-bit long is
// sufficient; this reference uses a 64-bit accumulator (with a printInt64 helper)
// to stay exact indefinitely. RESET zeroes all stats. A malformed/empty/out-of-range
// line replies ERR and changes nothing. An overlong line is discarded through its
// terminator with a single ERR.

const int MAX_LINE = 15;

char line[MAX_LINE + 1];
int len = 0;
bool overlong = false;

long long sumTotal = 0;   // 64-bit: exact well past 100000 full-magnitude samples
unsigned long count = 0;
long minV = 0, maxV = 0;

void printInt64(long long v) {
  if (v < 0) { Serial.print('-'); v = -v; }
  char tmp[20];
  int i = 0;
  if (v == 0) { Serial.print('0'); return; }
  unsigned long long u = (unsigned long long)v;
  while (u > 0) { tmp[i++] = char('0' + (int)(u % 10)); u /= 10; }
  while (i > 0) Serial.print(tmp[--i]);
}

void report() {
  Serial.print("N=");
  Serial.print(count);
  Serial.print(" SUM=");
  printInt64(sumTotal);
  Serial.print(" MIN=");
  Serial.print(minV);
  Serial.print(" MAX=");
  Serial.print(maxV);
  Serial.print('\n');
}

void resetStats() {
  sumTotal = 0;
  count = 0;
  minV = 0;
  maxV = 0;
  report();
}

void processLine() {
  line[len] = '\0';
  if (len == 5 && strcmp(line, "RESET") == 0) { resetStats(); return; }
  if (len == 0) { Serial.println("ERR"); return; }

  int i = 0;
  bool neg = false;
  if (line[0] == '-') { neg = true; i = 1; if (len == 1) { Serial.println("ERR"); return; } }
  long val = 0;
  for (; i < len; i++) {
    if (line[i] < '0' || line[i] > '9') { Serial.println("ERR"); return; }
    val = val * 10 + (line[i] - '0');
    if (val > 100000L) { Serial.println("ERR"); return; } // overflow guard for parse
  }
  if (neg) val = -val;
  if (val < -32768L || val > 32767L) { Serial.println("ERR"); return; }

  count++;
  sumTotal += (long long)val;
  if (count == 1) { minV = val; maxV = val; }
  else { if (val < minV) minV = val; if (val > maxV) maxV = val; }
  report();
}

void setup() {
  Serial.begin(115200);
}

void loop() {
  while (Serial.available()) {
    char c = Serial.read();
    if (c == '\r') continue;
    if (c == '\n') {
      if (overlong) { Serial.println("ERR"); overlong = false; }
      else processLine();
      len = 0;
      continue;
    }
    if (len >= MAX_LINE) overlong = true; // stop storing; wait for the terminator
    else line[len++] = c;
  }
}

// serial_control_protocol (OS-D2-07) — reference solution.
// Line-oriented control protocol @115200. Active-high LED on D7, PWM on D3, both
// start 0. Commands (LF/CRLF): "LED ON", "LED OFF", "PWM n" (0..255), "STATUS".
// Leading/trailing spaces ignored, command words case-insensitive, state persists.
// Malformed/unknown/missing-arg/non-decimal/out-of-range → ERR, change nothing.
// Every reply ends with a newline. Overlong line → discard to terminator, ERR once.

const int LED_PIN = 7;
const int PWM_PIN = 3;
const int MAX_LINE = 20;

char line[MAX_LINE + 1];
int len = 0;
bool overlong = false;

bool ledOn = false;
int pwmVal = 0;

// Uppercase a token in place (command words are case-insensitive; digits unaffected).
void upcase(char* s) {
  for (; *s; s++) if (*s >= 'a' && *s <= 'z') *s -= 32;
}

// Parse an unsigned decimal 0..255; return -1 on any non-digit or overflow/empty.
int parseByte(const char* s) {
  if (!*s) return -1;
  long v = 0;
  for (; *s; s++) {
    if (*s < '0' || *s > '9') return -1;
    v = v * 10 + (*s - '0');
    if (v > 255) return -1;
  }
  return (int)v;
}

void processLine() {
  line[len] = '\0';
  // Split into up to two space-delimited tokens, skipping leading/trailing/extra spaces.
  char* tokens[3];
  int nTok = 0;
  char* p = line;
  while (*p && nTok < 3) {
    while (*p == ' ') p++;
    if (!*p) break;
    tokens[nTok++] = p;
    while (*p && *p != ' ') p++;
    if (*p) *p++ = '\0';
  }
  // reject anything with a 3rd token
  bool extra = false;
  while (*p) { if (*p != ' ') { extra = true; break; } p++; }

  if (nTok == 0 || extra) { Serial.println("ERR"); return; }
  upcase(tokens[0]);

  if (nTok == 1 && strcmp(tokens[0], "STATUS") == 0) {
    Serial.print("STATUS LED=");
    Serial.print(ledOn ? "ON" : "OFF");
    Serial.print(" PWM=");
    Serial.println(pwmVal);
    return;
  }
  if (nTok == 2 && strcmp(tokens[0], "LED") == 0) {
    upcase(tokens[1]);
    if (strcmp(tokens[1], "ON") == 0) { ledOn = true; digitalWrite(LED_PIN, HIGH); Serial.println("OK LED=ON"); return; }
    if (strcmp(tokens[1], "OFF") == 0) { ledOn = false; digitalWrite(LED_PIN, LOW); Serial.println("OK LED=OFF"); return; }
  }
  if (nTok == 2 && strcmp(tokens[0], "PWM") == 0) {
    int n = parseByte(tokens[1]);
    if (n >= 0) {
      pwmVal = n;
      analogWrite(PWM_PIN, pwmVal);
      Serial.print("OK PWM=");
      Serial.println(pwmVal);
      return;
    }
  }
  Serial.println("ERR");
}

void setup() {
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, LOW);
  pinMode(PWM_PIN, OUTPUT);
  analogWrite(PWM_PIN, 0);
  Serial.begin(115200);
}

void loop() {
  while (Serial.available()) {
    char c = Serial.read();
    if (c == '\r') continue;
    if (c == '\n') {
      if (overlong) { Serial.println("ERR"); overlong = false; }
      else processLine();
      len = 0;
      continue;
    }
    if (len >= MAX_LINE) overlong = true;
    else line[len++] = c;
  }
}

// four_mode_indicator (OS-D3-01) — reference solution.
// Button D2 (INPUT_PULLUP, 30 ms debounce) advances one mode per press:
//   0 OFF (LED low), 1 SLOW 1 Hz, 2 MEDIUM 2 Hz, 3 FAST 4 Hz, then wraps to OFF.
// Active-high LED on D4, active buzzer on D3. Each accepted press pulses the buzzer
// HIGH for 50 ms. Blinking, debounce, and buzzer timing all run concurrently
// (non-blocking).

const int BTN_PIN = 2;
const int LED_PIN = 4;
const int BUZ_PIN = 3;
const unsigned long DEBOUNCE_MS = 30;
const unsigned long BUZZ_MS = 50;

// Half-period per mode (ms); 0 = no blink.
const unsigned long HALF_MS[4] = { 0, 500, 250, 125 };

int mode = 0;
int stableBtn = HIGH, lastReading = HIGH;
unsigned long lastChangeMs = 0;

bool ledOn = false;
unsigned long ledT = 0;

bool buzzing = false;
unsigned long buzStart = 0;

void setup() {
  pinMode(BTN_PIN, INPUT_PULLUP);
  pinMode(LED_PIN, OUTPUT);
  pinMode(BUZ_PIN, OUTPUT);
  digitalWrite(LED_PIN, LOW);
  digitalWrite(BUZ_PIN, LOW);
}

void loop() {
  unsigned long now = millis();

  // Debounce → advance one mode per accepted press.
  int reading = digitalRead(BTN_PIN);
  if (reading != lastReading) { lastReading = reading; lastChangeMs = now; }
  if (now - lastChangeMs >= DEBOUNCE_MS && reading != stableBtn) {
    stableBtn = reading;
    if (stableBtn == LOW) {                 // accepted press
      mode = (mode + 1) % 4;
      ledOn = false; digitalWrite(LED_PIN, LOW); ledT = now; // restart blink phase
      buzzing = true; buzStart = now; digitalWrite(BUZ_PIN, HIGH); // pulse buzzer
    }
  }

  // Buzzer pulse off after 50 ms (non-blocking).
  if (buzzing && now - buzStart >= BUZZ_MS) { buzzing = false; digitalWrite(BUZ_PIN, LOW); }

  // Blink per mode.
  unsigned long half = HALF_MS[mode];
  if (half == 0) {
    if (ledOn) { ledOn = false; digitalWrite(LED_PIN, LOW); }
  } else if (now - ledT >= half) {
    ledT = now; ledOn = !ledOn; digitalWrite(LED_PIN, ledOn);
  }
}

// reaction_timer_fsm (OS-D3-03) — reference solution.
// START button D2, STOP button D3 (both INPUT_PULLUP, 30 ms debounce). Cue LED D8.
// IDLE → accepted START starts a 1000 ms wait. A STOP during the wait is a false
// start: keep the LED off and print FALSE_START. Otherwise the LED turns on after
// 1000 ms; the first accepted STOP after that turns it off and prints
// REACTION_MS=<ms since the LED turned on>, then returns to IDLE. Extra STARTs while
// active and extra STOPs while IDLE are ignored.

const int START_BTN = 2;
const int STOP_BTN = 3;
const int LED_PIN = 8;
const unsigned long DEBOUNCE_MS = 30;
const unsigned long WAIT_MS = 1000;

int sStable = HIGH, sLast = HIGH; unsigned long sChange = 0;
int pStable = HIGH, pLast = HIGH; unsigned long pChange = 0;

enum State { IDLE, WAITING, REACT };
State state = IDLE;
unsigned long waitStart = 0, ledOnTime = 0;

// Returns true once, on a debounced press (HIGH→LOW that has been stable 30 ms).
bool pressed(int pin, int &stable, int &last, unsigned long &change) {
  int r = digitalRead(pin);
  if (r != last) { last = r; change = millis(); }
  if (millis() - change >= DEBOUNCE_MS && r != stable) {
    stable = r;
    if (stable == LOW) return true;
  }
  return false;
}

void setup() {
  pinMode(START_BTN, INPUT_PULLUP);
  pinMode(STOP_BTN, INPUT_PULLUP);
  pinMode(LED_PIN, OUTPUT);
  digitalWrite(LED_PIN, LOW);
  Serial.begin(115200);
}

void loop() {
  bool startPress = pressed(START_BTN, sStable, sLast, sChange);
  bool stopPress = pressed(STOP_BTN, pStable, pLast, pChange);
  unsigned long now = millis();

  if (state == IDLE) {
    if (startPress) { state = WAITING; waitStart = now; } // extra STOP ignored
  } else if (state == WAITING) {
    if (stopPress) { Serial.println("FALSE_START"); state = IDLE; } // false start
    else if (now - waitStart >= WAIT_MS) { state = REACT; digitalWrite(LED_PIN, HIGH); ledOnTime = now; }
    // extra START ignored
  } else { // REACT
    if (stopPress) {
      digitalWrite(LED_PIN, LOW);
      Serial.print("REACTION_MS=");
      Serial.println(now - ledOnTime);
      state = IDLE;
    }
    // extra START ignored
  }
}

// appliance_cycle_fsm (OS-D3-04) — reference solution.
// Door switch D2 (closed = LOW, INPUT_PULLUP). START/CANCEL button D3 (INPUT_PULLUP,
// 30 ms debounce). Active-high outputs FILL D6, MOTOR D7, DRAIN D8. Serial @115200.
// IDLE (all LOW): a debounced press starts a cycle only if the door is closed;
// otherwise print STATE=DOOR_OPEN. Cycle, no overlap: FILL 300 ms (STATE=FILL),
// MOTOR 600 ms (STATE=WASH), DRAIN 300 ms (STATE=DRAIN), then all LOW + STATE=DONE.
// If the door opens OR the button is pressed during a cycle: abort within 20 ms —
// all LOW, STATE=ABORT, back to IDLE.

const int DOOR_PIN = 2;
const int BTN_PIN = 3;
const int FILL_PIN = 6;
const int MOTOR_PIN = 7;
const int DRAIN_PIN = 8;
const unsigned long DEBOUNCE_MS = 30;

enum State { IDLE, S_FILL, S_WASH, S_DRAIN };
State state = IDLE;
unsigned long stateStart = 0;

int bStable = HIGH, bLast = HIGH; unsigned long bChange = 0;

bool buttonPressed() {
  int r = digitalRead(BTN_PIN);
  if (r != bLast) { bLast = r; bChange = millis(); }
  if (millis() - bChange >= DEBOUNCE_MS && r != bStable) {
    bStable = r;
    if (bStable == LOW) return true;
  }
  return false;
}

bool doorClosed() { return digitalRead(DOOR_PIN) == LOW; }

void allOff() {
  digitalWrite(FILL_PIN, LOW);
  digitalWrite(MOTOR_PIN, LOW);
  digitalWrite(DRAIN_PIN, LOW);
}

void setup() {
  pinMode(DOOR_PIN, INPUT_PULLUP);
  pinMode(BTN_PIN, INPUT_PULLUP);
  pinMode(FILL_PIN, OUTPUT);
  pinMode(MOTOR_PIN, OUTPUT);
  pinMode(DRAIN_PIN, OUTPUT);
  allOff();
  Serial.begin(115200);
}

void loop() {
  bool press = buttonPressed();
  unsigned long now = millis();

  // Abort: door opened or a button press during any active stage (within one loop).
  if (state != IDLE && (!doorClosed() || press)) {
    allOff();
    Serial.println("STATE=ABORT");
    state = IDLE;
    return;
  }

  switch (state) {
    case IDLE:
      if (press) {
        if (doorClosed()) {
          allOff();
          digitalWrite(FILL_PIN, HIGH);
          Serial.println("STATE=FILL");
          state = S_FILL; stateStart = now;
        } else {
          Serial.println("STATE=DOOR_OPEN");
        }
      }
      break;
    case S_FILL:
      if (now - stateStart >= 300) {
        digitalWrite(FILL_PIN, LOW);
        digitalWrite(MOTOR_PIN, HIGH);
        Serial.println("STATE=WASH");
        state = S_WASH; stateStart = now;
      }
      break;
    case S_WASH:
      if (now - stateStart >= 600) {
        digitalWrite(MOTOR_PIN, LOW);
        digitalWrite(DRAIN_PIN, HIGH);
        Serial.println("STATE=DRAIN");
        state = S_DRAIN; stateStart = now;
      }
      break;
    case S_DRAIN:
      if (now - stateStart >= 300) {
        digitalWrite(DRAIN_PIN, LOW);
        Serial.println("STATE=DONE");
        state = IDLE;
      }
      break;
  }
}
